function z(f,e,n){const i=Math.pow(f-.25,2)+e*e;if(i*(i+(f-.25))<=.25*e*e||Math.pow(f+1,2)+e*e<=.0625)return n;let s=0,r=0,l=0;const u=4,d=Math.min(n,1e3);for(;l<d;){const t=s*s,a=r*r;if(t+a>u)break;r=2*s*r+e,s=t-a+f,l++}return l}self.onmessage=f=>{const{width:e,startY:n,endY:i,zoom:s,offsetX:r,offsetY:l,maxIter:u}=f.data,d=i-n,t=new Uint8ClampedArray(e*d*4);for(let a=n;a<i;a++)for(let c=0;c<e;c++){const b=c/s+r,w=a/s+l,h=z(b,w,u),o=((a-n)*e+c)*4;h<u?(t[o]=h*2,t[o+1]=h*5,t[o+2]=h*3,t[o+3]=255):(t[o]=0,t[o+1]=0,t[o+2]=0,t[o+3]=255)}self.postMessage({startY:n,chunkData:t.buffer},[t.buffer])};
